// components/Hero.jsx — Centered hero section with search bar
import React from "react";

export default function Hero({ searchQuery, onSearchChange }) {
  return (
    <section className="py-16 text-center px-5">
      <p className="text-xs font-mono text-accent tracking-widest uppercase mb-4">
        Aptitude · Quantitative · Logical
      </p>
      <h1 className="text-3xl sm:text-4xl font-semibold text-white mb-3 leading-tight">
        Crack Aptitude Easily 🚀
      </h1>
      <p className="text-gray-400 text-base mb-8 max-w-xl mx-auto">
        Master formulas, shortcuts, and practice problems for every aptitude topic.
        Learn smart, not hard.
      </p>

      {/* Search bar */}
      <div className="max-w-md mx-auto flex gap-2">
        <input
          type="text"
          placeholder="Search topics… e.g. Percentages"
          value={searchQuery}
          onChange={(e) => onSearchChange(e.target.value)}
          className="flex-1 bg-surface border border-border rounded px-4 py-2.5 text-sm text-white placeholder-muted focus:outline-none focus:border-accent transition-colors"
        />
        <button className="bg-accent hover:bg-accent-hover text-white text-sm px-5 py-2.5 rounded transition-colors font-medium">
          Search
        </button>
      </div>
    </section>
  );
}
